def balanced(s):
    """Return True if the parentheses in the string are balanced."""
    stack = []
    for char in s:
        if char == '(':
            stack.append(char)
        elif char == ')':
            if not stack:
                return False  # edge case: no matching opening parenthesis
            stack.pop()
    return not stack  # an empty stack means all parentheses were matched
